from sys import stdin

n = int(stdin.readline())
s = stdin.readline()

def solve(s):
    res = 0
    i = 0
    while i < len(s):
        if s[i] == 'L':
            res += 1
            while i < len(s) and s[i] == 'L':
                i += 1
        else:
            i += 1
            while i < len(s) and s[i] == '.':
                i += 1
            if i < len(s) and s[i] == 'R':
                res += 1
                while i < len(s) and s[i] == 'R':
                    i += 1
            else:
                while i < len(s) and s[i] == '.':
                    i += 1
    return res

print(solve(s))
